                    match store
                        .record_protocol_binding_snapshot(
                            super::TASKFLOW_PROTOCOL_BINDING_SCENARIO,
                            super::TASKFLOW_PROTOCOL_BINDING_AUTHORITY,
                            &rows,
                        )
                        .await
                    {
